ACTIONS = [{'kind': 'skip', 'token_name': None, 'raw': 'return lexbuf', 'argument': None}, {'kind': 'return_name', 'token_name': 'KW_TRUE', 'raw': 'return KW_TRUE', 'argument': None}, {'kind': 'return_name', 'token_name': 'KW_FALSE', 'raw': 'return KW_FALSE', 'argument': None}, {'kind': 'return_name', 'token_name': 'KW_MAIN_START', 'raw': 'return KW_MAIN_START', 'argument': None}, {'kind': 'return_name', 'token_name': 'KW_ENDIF', 'raw': 'return KW_ENDIF', 'argument': None}, {'kind': 'return_name', 'token_name': 'KW_MAIN_END', 'raw': 'return KW_MAIN_END', 'argument': None}, {'kind': 'return_name', 'token_name': 'KW_PRINT', 'raw': 'return KW_PRINT', 'argument': None}, {'kind': 'return_name', 'token_name': 'KW_DECLARE', 'raw': 'return KW_DECLARE', 'argument': None}, {'kind': 'return_name', 'token_name': 'KW_INIT', 'raw': 'return KW_INIT', 'argument': None}, {'kind': 'return_name', 'token_name': 'KW_ASSIGN_START', 'raw': 'return KW_ASSIGN_START', 'argument': None}, {'kind': 'return_name', 'token_name': 'KW_ASSIGN_INIT', 'raw': 'return KW_ASSIGN_INIT', 'argument': None}, {'kind': 'return_name', 'token_name': 'KW_ASSIGN_END', 'raw': 'return KW_ASSIGN_END', 'argument': None}, {'kind': 'return_name', 'token_name': 'KW_CALL_ASSIGN', 'raw': 'return KW_CALL_ASSIGN', 'argument': None}, {'kind': 'return_name', 'token_name': 'KW_PLUS', 'raw': 'return KW_PLUS', 'argument': None}, {'kind': 'return_name', 'token_name': 'KW_MINUS', 'raw': 'return KW_MINUS', 'argument': None}, {'kind': 'return_name', 'token_name': 'KW_TIMES', 'raw': 'return KW_TIMES', 'argument': None}, {'kind': 'return_name', 'token_name': 'KW_DIV', 'raw': 'return KW_DIV', 'argument': None}, {'kind': 'return_name', 'token_name': 'KW_EQ', 'raw': 'return KW_EQ', 'argument': None}, {'kind': 'return_name', 'token_name': 'KW_GT', 'raw': 'return KW_GT', 'argument': None}, {'kind': 'return_name', 'token_name': 'KW_OR', 'raw': 'return KW_OR', 'argument': None}, {'kind': 'return_name', 'token_name': 'KW_AND', 'raw': 'return KW_AND', 'argument': None}, {'kind': 'return_name', 'token_name': 'KW_IF', 'raw': 'return KW_IF', 'argument': None}, {'kind': 'return_name', 'token_name': 'KW_ELSE', 'raw': 'return KW_ELSE', 'argument': None}, {'kind': 'return_name', 'token_name': 'KW_WHILE', 'raw': 'return KW_WHILE', 'argument': None}, {'kind': 'return_name', 'token_name': 'KW_ENDWHILE', 'raw': 'return KW_ENDWHILE', 'argument': None}, {'kind': 'return_name', 'token_name': 'KW_METHOD_DEF', 'raw': 'return KW_METHOD_DEF', 'argument': None}, {'kind': 'return_name', 'token_name': 'KW_METHOD_ARG', 'raw': 'return KW_METHOD_ARG', 'argument': None}, {'kind': 'return_name', 'token_name': 'KW_METHOD_NONVOID', 'raw': 'return KW_METHOD_NONVOID', 'argument': None}, {'kind': 'return_name', 'token_name': 'KW_METHOD_END', 'raw': 'return KW_METHOD_END', 'argument': None}, {'kind': 'return_name', 'token_name': 'KW_RETURN', 'raw': 'return KW_RETURN', 'argument': None}, {'kind': 'return_name', 'token_name': 'KW_CALL_VOID', 'raw': 'return KW_CALL_VOID', 'argument': None}, {'kind': 'return_call', 'token_name': 'STRING_LIT', 'raw': 'return STRING_LIT(lxm)', 'argument': 'lxm'}, {'kind': 'return_call', 'token_name': 'INT_LIT', 'raw': 'return INT_LIT(lxm)', 'argument': 'lxm'}, {'kind': 'return_call', 'token_name': 'IDENT', 'raw': 'return IDENT(lxm)', 'argument': 'lxm'}]
EOF_ACTION = {'kind': 'raise', 'token_name': None, 'raw': "raise('End of input')", 'argument': "'End of input'"}
EOF_SENTINEL = '<EOF>'
RULE_REGEXES = ["[' ' '\\t' '\\n' '\\r']", '"@NO PROBLEMO"', '"@I LIED"', '"IT\'S SHOWTIME"', '"YOU HAVE NO RESPECT FOR LOGIC"', '"YOU HAVE BEEN TERMINATED"', '"TALK TO THE HAND"', '"HEY CHRISTMAS TREE"', '"YOU SET US UP"', '"GET TO THE CHOPPER"', '"HERE IS MY INVITATION"', '"ENOUGH TALK"', '"GET YOUR ASS TO MARS"', '"GET UP"', '"GET DOWN"', '"YOU\'RE FIRED"', '"HE HAD TO SPLIT"', '"YOU ARE NOT YOU YOU ARE ME"', '"LET OFF SOME STEAM BENNET"', '"CONSIDER THAT A DIVORCE"', '"KNOCK KNOCK"', '"BECAUSE I\'M GOING TO SAY PLEASE"', '"BULLSHIT"', '"STICK AROUND"', '"CHILL"', '"LISTEN TO ME VERY CAREFULLY"', '"I NEED YOUR CLOTHES YOUR BOOTS AND YOUR MOTORCYCLE"', '"GIVE THESE PEOPLE AIR"', '"HASTA LA VISTA, BABY"', '"I\'LL BE BACK"', '"DO IT NOW"', 'str_lit', 'int_lit', 'ident']

@dataclass
class Token:
    type: str
    lexeme: str
    line: int
    column: int
    value: object = None

    def __str__(self) -> str:
        return self.type if self.value is None else f'{self.type}({self.value!r})'


class LexicalError(Exception):
    pass


class Lexer:
    def __init__(self, text: str):
        self.text = text
        self.pos = 0
        self.line = 1
        self.column = 1
        self._eof_done = False

    def tokenize(self) -> Iterator[Token]:
        while self.pos < len(self.text):
            token = self._next_token()
            if token is not None:
                yield token
        eof_token = self._handle_eof()
        if eof_token is not None:
            yield eof_token

    def _advance_position(self, lexeme: str) -> None:
        for ch in lexeme:
            if ch == '\n':
                self.line += 1
                self.column = 1
            else:
                self.column += 1
        self.pos += len(lexeme)

    def _diagnose_error(self, start: int, line: int, col: int) -> str:
        if start < len(self.text) and self.text[start] == '"':
            j = start + 1
            escaped = False
            while j < len(self.text):
                c = self.text[j]
                if escaped:
                    escaped = False
                elif c == '\\':
                    escaped = True
                elif c == '"':
                    break
                elif c == '\n':
                    return f'LEXICAL ERROR at line {line}, column {col}: Unterminated string literal'
                j += 1
        if start < len(self.text) and self.text[start].isdigit():
            j = start
            while j < len(self.text) and self.text[j].isdigit():
                j += 1
            if j < len(self.text) and self.text[j] == '.':
                if j + 1 >= len(self.text) or not self.text[j + 1].isdigit():
                    bad = self.text[start:j + 1]
                    return f"LEXICAL ERROR at line {line}, column {col}: Unrecognized token {bad!r} - float requires digits after the decimal point"
        if start < len(self.text) and self.text[start] == '.' and start > 0 and self.text[start - 1].isdigit():
            j = start - 1
            while j > 0 and self.text[j - 1].isdigit():
                j -= 1
            bad = self.text[j:start + 1]
            return f"LEXICAL ERROR at line {line}, column {col}: Unrecognized token {bad!r} - float requires digits after the decimal point"
        bad = self.text[start]
        return f"LEXICAL ERROR at line {line}, column {col}: Unrecognized character {bad!r}"

    def _next_token(self) -> Optional[Token]:
        state = 0
        i = self.pos
        start_line, start_col = self.line, self.column
        last_accept = None
        last_pos = self.pos
        consumed_eof = False
        while True:
            if i < len(self.text):
                ch = self.text[i]
                consumed = True
            elif not consumed_eof:
                ch = EOF_SENTINEL
                consumed = False
                consumed_eof = True
            else:
                break
            next_state = DFA_TRANSITIONS.get(state, {}).get(ch)
            if next_state is None:
                break
            state = next_state
            if consumed:
                i += 1
            if state in DFA_ACCEPTS:
                last_accept = DFA_ACCEPTS[state]
                last_pos = i
        if last_accept is None:
            raise LexicalError(self._diagnose_error(self.pos, start_line, start_col))
        lexeme = self.text[self.pos:last_pos]
        action = ACTIONS[last_accept]
        return self._apply_action(action, lexeme, start_line, start_col)

    def _run_raw_action(self, source: str, lxm: str):
        namespace = dict(globals())
        namespace.update({'lxm': lxm, 'lexbuf': None})
        func_src = 'def __yalex_action(lxm, lexbuf):\n' + '\n'.join('    ' + line for line in source.splitlines())
        exec(func_src, namespace)
        return namespace['__yalex_action'](lxm, None)

    def _apply_action(self, action, lexeme: str, start_line: int, start_col: int) -> Optional[Token]:
        kind = action['kind']
        self._advance_position(lexeme)
        if kind == 'skip':
            return None
        if kind == 'return_name':
            return Token(action['token_name'], lexeme, start_line, start_col)
        if kind == 'return_call':
            token_name = action['token_name']
            arg = (action.get('argument') or '').strip()
            value = lexeme if arg in ('lxm', 'lexeme') else None
            if value is None and arg:
                try:
                    value = eval(arg, dict(globals()), {'lxm': lexeme, 'lexeme': lexeme})
                except Exception:
                    value = lexeme
            return Token(token_name, lexeme, start_line, start_col, value=value)
        if kind == 'raise':
            expr = action.get('argument') or repr('End of input')
            try:
                value = eval(expr, dict(globals()), {'lxm': lexeme})
            except Exception:
                value = expr
            raise StopIteration(value)
        result = self._run_raw_action(action.get('raw', ''), lexeme)
        if result is None:
            return None
        if isinstance(result, Token):
            return result
        if isinstance(result, str):
            return Token(result, lexeme, start_line, start_col)
        return Token(type(result).__name__.upper(), lexeme, start_line, start_col, value=result)

    def _handle_eof(self) -> Optional[Token]:
        if self._eof_done:
            return None
        self._eof_done = True
        action = EOF_ACTION
        if not action:
            return None
        if action['kind'] == 'raise':
            return None
        if action['kind'] == 'return_name':
            return Token(action['token_name'], '', self.line, self.column)
        if action['kind'] == 'return_call':
            return Token(action['token_name'], '', self.line, self.column, value='')
        return None


def lex_file(path: str, with_lexeme: bool = False) -> int:
    text = Path(path).read_text(encoding='utf-8')
    lexer = Lexer(text)
    try:
        for token in lexer.tokenize():
            if with_lexeme:
                print(f'{token.type}	{token.lexeme!r}	(line={token.line}, col={token.column})')
            else:
                print(token.type)
        return 0
    except StopIteration:
        return 0
    except LexicalError as exc:
        print(str(exc))
        return 1


def main() -> int:
    parser = argparse.ArgumentParser(description='Generated lexer from YALex spec')
    parser.add_argument('input', help='Text file to lex')
    parser.add_argument('--with-lexeme', action='store_true', help='Print lexemes and positions')
    args = parser.parse_args()
    return lex_file(args.input, with_lexeme=args.with_lexeme)


if __name__ == '__main__':
    raise SystemExit(main())
